// Split comma-separated inputs into arrays, filtering empty strings
const toArr = val => val ? val.split(',').map(s => s.trim()).filter(Boolean) : [];

const cfg = $input.first().json;

return [{
  json: {
    name: toArr(cfg.names),
    email: toArr(cfg.emails),
    phone_number: toArr(cfg.phones),
    street_citystatezip: [],
    max_results: cfg.max_results || 1
  }
}];

// Parse CSV text into structured records
const csvText = $input.first().json.data || $input.first().json.body || '';

if (!csvText || typeof csvText !== 'string') {
  return [{ json: { error: 'No CSV data returned', runId: $('Store Run ID').item.json.runId } }];
}

const lines = csvText.trim().split('\n');
if (lines.length < 2) {
  return [{ json: { error: 'Empty CSV', runId: $('Store Run ID').item.json.runId } }];
}

// Parse header row, handling quoted fields
const parseRow = row => {
  const result = [];
  let inQuotes = false;
  let current = '';
  for (let i = 0; i < row.length; i++) {
    const ch = row[i];
    if (ch === '"') {
      inQuotes = !inQuotes;
    } else if (ch === ',' && !inQuotes) {
      result.push(current.trim());
      current = '';
    } else {
      current += ch;
    }
  }
  result.push(current.trim());
  return result;
};

const headers = parseRow(lines[0]);
const records = [];
const seenKeys = new Set();

for (let i = 1; i < lines.length; i++) {
  const values = parseRow(lines[i]);
  if (values.length < 2) continue;
  const record = {};
  headers.forEach((h, idx) => {
    record[h] = values[idx] || '';
  });
  // Deduplicate by name + primary_phone combination
  const dedupeKey = (record['name'] || '') + '|' + (record['primary_phone'] || record['phone'] || '');
  if (!seenKeys.has(dedupeKey)) {
    seenKeys.add(dedupeKey);
    records.push({ json: record });
  }
}

return records.length > 0 ? records : [{ json: { error: 'No records parsed', raw: csvText.substring(0, 200) } }];
